export const REMOVED_SEAT_IDS = new Set([
  "G-J-31",
  "G-J-32",
  "G-J-33",
  "G-J-34",
  "G-J-35",
  "G-J-36",
  "S6-L-6",
  "S6-L-7",
  "S6-R-6",
  "S6-R-7",
]);

export const PRE_BOOKED_SOFA_ROWS = ["S1", "S5"];

export function getPreBookedSeatIds() {
  const seats = [];
  sofaRows
    .filter((row) => PRE_BOOKED_SOFA_ROWS.includes(row.id))
    .forEach((row) => {
      for (let i = 1; i <= row.left; i += 1) seats.push(`${row.id}-L-${i}`);
      for (let i = 1; i <= row.right; i += 1) seats.push(`${row.id}-R-${i}`);
    });
  return seats;
}

export function getSeatCategory(cat) {
  if (cat === "platinum") return "Sofa Platinum";
  if (cat === "gold") return "Sofa Gold";
  if (cat === "chairGround" || cat === "chair-ground") return "Ground Chair";
  if (cat === "chairBalcony" || cat === "chair-balcony") return "First Floor Chair";
  return "Seat";
}

export function isSofaCategory(cat) {
  return cat === "platinum" || cat === "gold";
}

export function getSeatById(seatId) {
  const sofaMatch = /^(S\d+)-(L|R)-(\d+)$/.exec(seatId);
  if (sofaMatch) {
    const row = sofaRows.find((item) => item.id === sofaMatch[1]);
    if (!row) return null;
    return { id: seatId, label: sofaMatch[3], cat: row.cat, price: row.price, extraPrice: row.extraPrice || row.price };
  }

  const pdfSeat = PDF_LAYOUT.seats.find((seat) => seat.id === seatId);
  if (pdfSeat) {
    return { ...pdfSeat, extraPrice: pdfSeat.extraPrice || pdfSeat.price };
  }

  return null;
}
